// ====================================================================
// ALGORITMO: Z-SCORE TÉRMICO MULTI-SENSOR (Máximo Recall Aislado)
// ====================================================================

const N_VENTANA = 20;
const Z_CRITICO = 1.3; // Umbral hiper-sensible optimizado para Máximo Recall

let topic = msg.topic || "global"; // Clave unívoca de enrutamiento por sensor
let temp_actual = parseFloat(msg.payload.datos_sensores.temperatura_int_C);
if (isNaN(temp_actual)) return null;

// 1. ARQUITECTURA MULTI-TENANT: Recuperar el mapa de ventanas de la memoria RAM
let mapa_ventanas = context.get('mapa_ventanas_zscore') || {};
let ventana = mapa_ventanas[topic] || [];

// Inyección del dato actual en la ventana correspondiente a este sensor
ventana.push(temp_actual);
if (ventana.length > N_VENTANA) {
    ventana.shift(); // Mantenemos el tamaño de la ventana móvil
}

// Guardamos la ventana actualizada de este sensor específico en el mapa global
mapa_ventanas[topic] = ventana;
context.set('mapa_ventanas_zscore', mapa_ventanas);

// 2. SALVAGUARDA DE INICIALIZACIÓN (Arranque en frío)
if (ventana.length < N_VENTANA) {
    msg.prediccion_algoritmo = 0;
    msg.algoritmo_nombre = "Z-Score_Termico";
    return msg; // Esperamos a tener la ventana llena para operar matemáticamente
}

// 3. CÁLCULO DE LA MEDIA ESTADÍSTICA DE LA VENTANA
let suma = 0;
for (let i = 0; i < N_VENTANA; i++) suma += ventana[i];
let media = suma / N_VENTANA;

// 4. CÁLCULO DE LA DESVIACIÓN ESTÁNDAR
let suma_varianza = 0;
for (let i = 0; i < N_VENTANA; i++) {
    let diff = ventana[i] - media;
    suma_varianza += (diff * diff);
}
let desviacion = Math.sqrt(suma_varianza / N_VENTANA);

// 5. EVALUACIÓN DE LA DISTANCIA ESTADÍSTICA (Z-Score)
// Si la desviación es 0 (datos planos estables), el Z-Score es cero para evitar NaN
let z_score = (desviacion === 0) ? 0 : Math.abs((temp_actual - media) / desviacion);

// 6. DEFUSIFICACIÓN / DISPARO HIPIER-SENSITIVO
let prediccion = (z_score > Z_CRITICO) ? 1 : 0;

// Enrutamiento unificado de variables hacia el Evaluador Central
msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "Z-Score_Termico";

return msg;

// ====================================================================
// ALGORITMO: EWMA TÉRMICO MULTI-SENSOR (Máximo Recall Corregido)
// ====================================================================

const ALPHA = 0.50;        // Elevado: Otorga un 50% de peso al último evento leído
const UMBRAL_ERROR = 0.5;  // CORREGIDO: Tolerancia estricta de 0.5ºC para Máximo Recall

let topic = msg.topic || "global"; // Clave única para aislar cada sensor
let temp_actual = parseFloat(msg.payload.datos_sensores.temperatura_int_C);
if (isNaN(temp_actual)) return null;

// 1. ARQUITECTURA MULTI-TENANT: Recuperar el diccionario de estados de la RAM
let mapa_ewma = context.get('mapa_ewma') || {};
let ewma_anterior = mapa_ewma[topic];

// Inicialización en frío por software (para el primer mensaje de este sensor específico)
if (ewma_anterior === undefined) {
    ewma_anterior = temp_actual;
}

// 2. CÁLCULO DEL ERROR RESIDUAL ANALÍTICO
// Evaluamos la desviación del valor real frente a la predicción esperada (el EWMA previo)
let error_residual = Math.abs(temp_actual - ewma_anterior);

// 3. DEFUSIFICACIÓN / DISPARO HIPIER-SENSIBLE
let prediccion = (error_residual > UMBRAL_ERROR) ? 1 : 0;

// 4. ACTUALIZACIÓN DINÁMICA DEL ESTADO DEL SENSOR
let ewma_actual = (ALPHA * temp_actual) + ((1 - ALPHA) * ewma_anterior);
mapa_ewma[topic] = ewma_actual; // Guardamos el nuevo EWMA indexado por su Topic MQTT
context.set('mapa_ewma', mapa_ewma);

// Enrutamiento de variables unificadas hacia el Evaluador Central
msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "EWMA_Termico";

return msg;

// ====================================================================
// ALGORITMO: LÓGICA DIFUSA ADAPTATIVA, GENÉRICA Y AUTO-CALIBRADA (V2)
// ====================================================================

let caudal = parseFloat(msg.payload.datos_sensores.caudal_Lmin);
if (isNaN(caudal)) return null;

let topic = msg.topic || "global"; // Clave unívoca para aislar cada sensor (Multi-Tenant)
let ahora = new Date();
let hora_decimal = ahora.getHours() + (ahora.getMinutes() / 60);

// --------------------------------------------------------------------
// 1. MEMORIA TEMPORAL: Recuperar y actualizar la media móvil de fondo
// --------------------------------------------------------------------
let mapa_medias = context.get('mapa_medias_caudal') || {};
let media_anterior = mapa_medias[topic];

// Inicialización en frío por software
if (media_anterior === undefined || media_anterior === 0) {
    mapa_medias[topic] = caudal;
    context.set('mapa_medias_caudal', mapa_medias);

    msg.prediccion_algoritmo = 0;
    msg.algoritmo_nombre = "Logica_Difusa_Fugas";
    msg.riesgo_difuso_calculado = 0;
    msg.media_caudal_calculada = caudal;
    return msg;
}

// --------------------------------------------------------------------
// 2. FUSIFICACIÓN: VENTANA NOCTURNA (Trapezoide Difuso)
// --------------------------------------------------------------------
let mu_noche = 0.0;
if (hora_decimal >= 23 || hora_decimal < 5) {
    mu_noche = 1.0; // Plena madrugada
} else if (hora_decimal >= 5 && hora_decimal <= 6) {
    mu_noche = 1.0 - (hora_decimal - 5); // Rampa descendente de amanecer
} else if (hora_decimal >= 22 && hora_decimal < 23) {
    mu_noche = hora_decimal - 22; // Rampa ascendente de cierre
}

// --------------------------------------------------------------------
// 3. FUSIFICACIÓN: CAUDAL ADAPTATIVO (Ratio Genérico de Desviación)
// --------------------------------------------------------------------
let ratio = caudal / media_anterior;
let mu_caudal = 0.0;

// Ajustamos ligeramente los umbrales para capturar fugas reales (+15% a +50%)
const RATIO_MIN_SOSPECHA = 1.15;
const RATIO_MAX_SOSPECHA = 1.50;

if (ratio < RATIO_MIN_SOSPECHA) {
    mu_caudal = 0.0;
} else if (ratio >= RATIO_MIN_SOSPECHA && ratio <= RATIO_MAX_SOSPECHA) {
    mu_caudal = (ratio - RATIO_MIN_SOSPECHA) / (RATIO_MAX_SOSPECHA - RATIO_MIN_SOSPECHA);
} else {
    mu_caudal = 1.0;
}

// --------------------------------------------------------------------
// 4. INFERENCIA DIFUSA (Sistema de Reglas Concurrentes)
// --------------------------------------------------------------------
// Regla A (Nocturna): El riesgo se amplifica si coincide con la noche.
let riesgo_nocturno = mu_caudal * mu_noche;

// Regla B (Diurna/Crítica): Si el caudal supera el máximo ratio (mu_caudal -> 1), 
// es peligroso por sí mismo, independientemente de la hora.
let riesgo_absoluto = mu_caudal >= 0.8 ? mu_caudal : 0.0;

// Combinación mediante Co-Norma t (Máximo): Tomamos el escenario más crítico
let riesgo_fuga = Math.max(riesgo_nocturno, riesgo_absoluto);

// DEFUSIFICACIÓN: Umbral de decisión balanceado
let prediccion = (riesgo_fuga >= 0.40) ? 1 : 0;

// --------------------------------------------------------------------
// 5. APRENDIZAJE CONTINUO DINÁMICO (Anti-Contaminación de la Media)
// --------------------------------------------------------------------
// Si detectamos una fuga (prediccion === 1), congelamos temporalmente el 
// aprendizaje (ALPHA = 0) para que la media no "absorba" la fuga y altere los datos en Grafana.
let alpha = (prediccion === 1) ? 0.0 : 0.01;
let media_nueva = (alpha * caudal) + ((1 - alpha) * media_anterior);

mapa_medias[topic] = media_nueva;
context.set('mapa_medias_caudal', mapa_medias);

// Enrutamiento unificado de variables hacia el Evaluador Central y Grafana
msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "Logica_Difusa_Fugas";
msg.riesgo_difuso_calculado = Math.round(riesgo_fuga * 100) / 100;
msg.media_caudal_calculada = Math.round(media_nueva * 100) / 100;

return msg;

// ====================================================================
// NODO EVALUADOR CIENTÍFICO CENTRAL (Matriz Viva en RAM)
// ====================================================================

let prediccion = msg.prediccion_algoritmo;
let algoritmo = msg.algoritmo_nombre || "Desconocido";

// 1. OBTENER LA VERDAD (Ground Truth) DEL ESP32
let realidad = 0;
if (msg.payload.ground_truth && msg.payload.ground_truth.estado_anomalo !== undefined) {
    // Si el ESP32 manda 'true' o un 1 numérico, forzamos realidad a 1. Si no, a 0.
    realidad = (msg.payload.ground_truth.estado_anomalo === true || msg.payload.ground_truth.estado_anomalo == 1) ? 1 : 0;
}

// 2. GESTIÓN DE LA MATRIZ DE CONFUSIÓN VIVA
let matriz = context.get(algoritmo) || { tp: 0, fp: 0, fn: 0, tn: 0 };

// Cruce analítico: ¿Acertó el algoritmo?
if (prediccion === 1 && realidad === 1) matriz.tp++;        // Verdadero Positivo
else if (prediccion === 1 && realidad === 0) matriz.fp++;   // Falsa Alarma
else if (prediccion === 0 && realidad === 1) matriz.fn++;   // Falso Negativo
else if (prediccion === 0 && realidad === 0) matriz.tn++;   // Verdadero Negativo

context.set(algoritmo, matriz);

// 3. CÁLCULO SEGURO DE MÉTRICAS (NaN Guard)
const precision_raw = (matriz.tp + matriz.fp) === 0 ? 0.0 : (matriz.tp / (matriz.tp + matriz.fp));
const recall_raw = (matriz.tp + matriz.fn) === 0 ? 0.0 : (matriz.tp / (matriz.tp + matriz.fn));
const f1_raw = (precision_raw + recall_raw) === 0 ? 0.0 : (2 * (precision_raw * recall_raw) / (precision_raw + recall_raw));

// Redondeos limpios para la base de datos
let precision_opt = Math.round(precision_raw * 10000) / 10000;
let recall_opt = Math.round(recall_raw * 10000) / 10000; // <--- ¡CORREGIDO!
let f1_opt = Math.round(f1_raw * 10000) / 10000;

// 4. CÁLCULO DE LATENCIA COMPUTACIONAL
let latencia_seg = 0.0;
if (msg.payload.tiempo_inicio) {
    let latencia_ms = Date.now() - msg.payload.tiempo_inicio;
    latencia_seg = Math.round((latencia_ms / 1000) * 1000) / 1000;
}

// 5. EMPAQUETADO FINAL DE SALIDA PARA INFLUXDB Y CSV
let payload_final = {
    algoritmo: algoritmo,
    tp: matriz.tp,
    fp: matriz.fp,
    fn: matriz.fn,
    tn: matriz.tn,
    precision: precision_opt,
    recall: recall_opt,      // <--- ¡AÑADIDO AL PAYLOAD!
    f1_score: f1_opt,
    latencia_media: latencia_seg
};

msg.payload = payload_final;
msg.csv_line = `${algoritmo};${(precision_opt * 100).toFixed(2)}%;${f1_opt.toFixed(4)};${latencia_seg.toFixed(1)} seg;${matriz.tp};${matriz.fp};${matriz.fn}\n`;

return msg;

// 1. Asegurar que leemos el objeto correctamente
let paquete = typeof msg.payload === "string" ? JSON.parse(msg.payload) : msg.payload;

// 2. Extraer los METADATOS (Las etiquetas o Tags para InfluxDB)
let meta = paquete.metadatos || {};

let etiquetas = {
    isla: meta.isla || "Desconocida",
    municipio: meta.municipio || "Desconocido",
    tipo_instalacion: meta.tipo_instalacion || "Desconocida",
    centro: meta.centro || "Desconocido",
    zona: meta.zona || "Desconocida",
    id_dispositivo: meta.id_dispositivo || "Unico",
    tipo_sensor: meta.tipo_sensor || "Desconocido"
};

// 3. Extraer los CAMPOS numéricos (Fields para InfluxDB) del nuevo bloque "datos_sensores"
let datos = paquete.datos_sensores || {};
let campos = {};

// Mapeamos los nombres nuevos a las columnas de tu base de datos
if (datos.temperatura_int_C !== undefined) campos.temperatura_interior = datos.temperatura_int_C;
if (datos.temperatura_ext_C !== undefined) campos.temperatura_exterior = datos.temperatura_ext_C;
if (datos.potencia_W !== undefined) campos.consumo_electrico_W = datos.potencia_W;
if (datos.caudal_Lmin !== undefined) campos.caudal_agua_Lmin = datos.caudal_Lmin;

// 4. Empaquetar y enviar a InfluxDB (Solo si encontró datos numéricos)
if (Object.keys(campos).length > 0) {
    msg.payload = [
        campos,     // Los valores numéricos puros (Fields)
        etiquetas   // Las etiquetas de categorización (Tags)
    ];
    return msg;
} else {
    // Si no detectó los datos, bloquea el flujo para no mandar basura a InfluxDB
    return null;
}

// Rescatamos la línea pre-formateada que fabricó el Evaluador
if (msg.csv_line) {
    // El nodo 'File' de Node-RED siempre escribe lo que haya en msg.payload
    msg.payload = msg.csv_line;
    return msg;
}

// Si por algún motivo no hay línea, abortamos para no escribir basura
return null;

let campos = {
    tp: msg.payload.tp,
    fp: msg.payload.fp,
    fn: msg.payload.fn,
    tn: msg.payload.tn,
    precision: msg.payload.precision,
    recall: msg.payload.recall, // <--- AÑADIDO AQUÍ TAMBIÉN
    f1_score: msg.payload.f1_score,
    latencia_media: msg.payload.latencia_media
};

let etiquetas = {
    algoritmo: msg.payload.algoritmo
};

msg.payload = [campos, etiquetas];
return msg;

// Recuperamos el array preparado para InfluxDB [fields, tags]
let fields = msg.payload[0];
let tags = msg.payload[1];

// Diccionario geográfico con coordenadas exactas de Canarias
const baseGeografica = {
    "Puerto_Rosario": { nombre: "Puerto del Rosario", lat: 28.5008, lon: -13.8628 },
    "La_Orotava": { nombre: "La Orotava", lat: 28.3902, lon: -16.5235 },
    "La_Laguna": { nombre: "La Laguna", lat: 28.4871, lon: -16.3149 },
    "Las_Palmas": { nombre: "Las Palmas", lat: 28.1235, lon: -15.4363 }
};

let itemOriginal = tags.municipio;

if (baseGeografica[itemOriginal]) {
    // 1. Guardamos el nombre limpio en los Tags
    tags.municipio = baseGeografica[itemOriginal].nombre;

    // 2. Inyectamos la Latitud y Longitud como variables NUMÉRICAS en los Fields
    fields.latitude = baseGeografica[itemOriginal].lat;
    fields.longitude = baseGeografica[itemOriginal].lon;
}

// Reensamblamos el mensaje para el nodo 'influxdb out'
msg.payload = [fields, tags];
return msg;

// Forzamos la obtención de la fecha en formato UTC puro
var ahora = new Date();
var utc_milisegundos = ahora.getTime() + (ahora.getTimezoneOffset() * 60000);

msg.payload = { "t": utc_milisegundos };
return msg;

// Le decimos al navegador que esto es un archivo descargable
msg.headers = {
    'Content-Type': 'text/csv',
    'Content-Disposition': 'attachment; filename="resultados_tfm.csv"'
};
return msg;

// ====================================================================
// NODO: FILTRAR Y EXTRAER ALERTAS (Extracción Geográfica y Temporal)
// ====================================================================

// Solo actuamos si el algoritmo ha detectado una anomalía real (Predicción = 1)
if (msg.prediccion_algoritmo === 1) {

    let algoritmo = msg.algoritmo_nombre || "Desconocido";
    let topic = msg.topic || ""; // Ejemplo: "canarias/Hospital/Gran_Canaria/.../datos"

    // 1. EXTRAER LOCALIZACIÓN DINÁMICA DESDE EL TOPIC MQTT
    // Dividimos el topic por barras inclinadas para extraer cada nivel jerárquico
    let niveles = topic.split('/');

    let region = niveles[0] || "No especificado";
    let tipo_infra = niveles[1] || "No especificado";
    let isla = niveles[2] || "No especificado";
    let municipio = niveles[3] || "No especificado";
    let centro = niveles[4] || "No especificado";
    let zona = niveles[5] || "No especificado";
    let dispositivo = niveles[6] || "No especificado";

    // 2. CAPTURAR LA HORA EXACTA DEL SUCESO (Formato ISO para Base de Datos)
    let hora_iso = new Date().toISOString();

    // 3. CAPTURAR EL VALOR QUE PROVOCÓ LA ALERTA
    let valor_disparador = 0.0;
    if (msg.payload && msg.payload.datos_sensores) {
        // Si es telemetría térmica o de caudal, guardamos el valor correspondiente
        valor_disparador = msg.payload.datos_sensores.temperatura_int_C || msg.payload.datos_sensores.caudal_Lmin || 0.0;
    }

    // 4. EMPAQUETAR ESTRUCTURA ESTRICTA PARA INFLUXDB (Measurement: alertas_anomalias)
    msg.payload = [
        {
            // Campos numéricos o de texto descriptivo amplio
            valor_detectado: parseFloat(valor_disparador),
            mensaje_alerta: `Anomalía crítica detectada por ${algoritmo}`,
            hora_local: new Date().toLocaleString("es-ES", { timeZone: "Atlantic/Canary" }) // Hora legible Canaria
        },
        {
            // Tags (Índices de búsqueda rápida en InfluxDB y Grafana)
            algoritmo: algoritmo,
            region: region,
            tipo_infraestructura: tipo_infra,
            isla: isla,
            municipio: municipio,
            centro_operativo: centro,
            zona_especifica: zona,
            sensor_id: dispositivo
        }
    ];

    // Forzamos a InfluxDB a usar la hora exacta en la que se generó esta alerta
    msg.timestamp = new Date(hora_iso);

    return msg; // Alerta aprobada -> Pasa a la base de datos
}

// Si el algoritmo dice que todo está normal (0), destruimos el mensaje silenciosamente
return null;
